// Inline PWA manifest jako blob
const manifestData = {
  "name": "DartPro – Trening Darta",
  "short_name": "DartPro",
  "description": "Aplikacja do treningu i śledzenia postępów w darcie",
  "start_url": "./index.html",
  "display": "standalone",
  "background_color": "#0a0a0f",
  "theme_color": "#0a0a0f",
  "orientation": "portrait",
  "icons": [
    {"src": "data:image/png;base64,", "sizes": "192x192", "type": "image/png", "purpose": "any maskable"},
    {"src": "data:image/png;base64,", "sizes": "512x512", "type": "image/png", "purpose": "any maskable"}
  ]
};
const manifestBlob = new Blob([JSON.stringify(manifestData)], {type:'application/json'});
const manifestURL = URL.createObjectURL(manifestBlob);
document.getElementById('pwa-manifest').setAttribute('href', manifestURL);
